// copy-to-clipboard-button.tsx
'use client';

import {Button} from '@/components/ui/button';
import {cn} from '@/lib/utils';

import {Check, ClipboardCopy} from 'lucide-react';
import * as React from 'react';

type CopyToClipboardButtonProps = Omit<
  React.ComponentProps<typeof Button>,
  'onClick' | 'children' | 'aria-label'
> & {
  /** Text to copy to the clipboard */
  text: string;
  /** Show "Copy" / "Copied!" text label. @default false */
  showLabel?: boolean;
  /** Callback fired after successful copy */
  onCopy?: () => void;
};

function CopyToClipboardButton({
  text,
  showLabel = false,
  onCopy,
  className,
  size,
  ...props
}: CopyToClipboardButtonProps) {
  const [copied, setCopied] = React.useState(false);

  React.useEffect(() => {
    if (!copied) return;
    const timer = setTimeout(() => setCopied(false), 2000);
    return () => clearTimeout(timer);
  }, [copied]);

  const handleCopy = React.useCallback(async () => {
    try {
      await navigator.clipboard.writeText(text);
      setCopied(true);
      onCopy?.();
    } catch {
      console.error('[CopyToClipboardButton] Failed to copy to clipboard');
    }
  }, [text, onCopy]);

  return (
    <Button
      data-slot="copy-to-clipboard-button"
      variant="ghost"
      size={size ?? (showLabel ? 'sm' : 'icon-sm')}
      onClick={handleCopy}
      aria-label={copied ? 'Copied!' : 'Copy to clipboard'}
      className={cn(className)}
      {...props}
    >
      {copied ? (
        <Check className="size-3.5" aria-hidden="true" />
      ) : (
        <ClipboardCopy className="size-3.5" aria-hidden="true" />
      )}
      {showLabel && <span>{copied ? 'Copied!' : 'Copy'}</span>}
    </Button>
  );
}

export {CopyToClipboardButton};
export type {CopyToClipboardButtonProps};
